<!-- 功能说明
管理端客户管理核心页面，支持客户列表多条件筛选（用户类型、下单状态）、客户详情查看、客户备注，
展示客户基础信息（昵称、联系方式、用户类型）及关键行为数据（首次登录、最近下单），
核心对接客户列表、客户详情接口，为运营提供客户数据支撑。 -->


<template>
  <view class="customer-manage-container">
    <!-- 页面头部 -->
    <view class="page-header">
      <text class="header-title">客户管理</text>
    </view>

    <!-- 筛选区域 -->
    <view class="filter-container">
      <!-- 用户类型筛选 -->
      <picker 
        class="filter-picker"
        :range="userTypeList"
        :range-key="'label'"
        :value="filterForm.userTypeIndex"
        @change="handleUserTypeChange"
      >
        <view class="picker-content">
          <text>{{userTypeList[filterForm.userTypeIndex].label}}</text>
          <image src="/static/images/icon-arrow-down.png" class="picker-icon"></image>
        </view>
      </picker>

      <!-- 下单状态筛选 -->
      <picker 
        class="filter-picker"
        :range="orderStatusList"
        :range-key="'label'"
        :value="filterForm.orderStatusIndex"
        @change="handleOrderStatusChange"
      >
        <view class="picker-content">
          <text>{{orderStatusList[filterForm.orderStatusIndex].label}}</text>
          <image src="/static/images/icon-arrow-down.png" class="picker-icon"></image>
        </view>
      </picker>

      <!-- 搜索区域 -->
      <view class="search-container">
        <image src="/static/images/icon-search.png" class="search-icon"></image>
        <input 
          class="search-input" 
          v-model="filterForm.keyword" 
          placeholder="请输入联系电话搜索"
          @input="debounceSearch"
        ></input>
        <button class="reset-btn" @click="resetFilter" v-if="filterForm.keyword">重置</button>
      </view>
    </view>

    <!-- 客户列表 -->
    <view class="customer-list" v-if="customerList.length > 0">
      <view class="customer-item" v-for="(item, index) in customerList" :key="item.id" @click="goToCustomerDetail(item.id)">
        <image :src="item.avatar || '/static/images/default-avatar.png'" class="customer-avatar"></image>
        <view class="customer-info">
          <view class="info-top">
            <text class="customer-name">{{item.nickname || '匿名用户'}}</text>
            <text class="customer-tag" :class="item.userType === 'ENTERPRISE' ? 'tag-enterprise' : 'tag-personal'">
              {{item.userType === 'ENTERPRISE' ? '企业客户' : '个人客户'}}
            </text>
          </view>
          <view class="info-middle">
            <text class="info-label">联系电话：</text>
            <text class="info-value">{{item.phone || '未绑定'}}</text>
          </view>
          <view class="info-bottom">
            <text class="info-label">首次登录：</text>
            <text class="info-value">{{formatTime(item.firstLoginTime) || '-'}}</text>
            <text class="info-label" style="margin-left: 20rpx;">最近下单：</text>
            <text class="info-value">{{formatTime(item.lastOrderTime) || '无'}}</text>
          </view>
        </view>
        <image src="/static/images/icon-arrow-right.png" class="arrow-icon"></image>
      </view>
    </view>

    <!-- 空列表状态 -->
    <view class="empty-list" v-else>
      <image src="/static/images/empty-customer.png" class="empty-img"></image>
      <text class="empty-text">暂无符合条件的客户</text>
    </view>

    <!-- 加载更多 -->
    <view class="load-more" v-if="isLoadingMore">
      <text class="load-text">加载中...</text>
    </view>
  </view>
</template>

<script setup>
import { ref } from 'vue';
import { onLoad, onShow } from '@dcloudio/uni-app';
import { useUserStore } from '@/store/modules/userStore';
import request from '@/utils/request';

// 状态管理
const userStore = useUserStore();

// 页面数据
const userTypeList = ref([
  { label: '全部用户', value: '' },
  { label: '个人客户', value: 'PERSONAL' },
  { label: '企业客户', value: 'ENTERPRISE' }
]);
const orderStatusList = ref([
  { label: '全部状态', value: '' },
  { label: '已下单', value: 'HAS_ORDER' },
  { label: '未下单', value: 'NO_ORDER' }
]);
const filterForm = ref({
  userTypeIndex: 0,
  orderStatusIndex: 0,
  keyword: '',
  pageNum: 1,
  pageSize: 10
});
const customerList = ref([]);
const isLoadingMore = ref(false);
const hasMore = ref(true);
let searchTimer = null;

// 页面加载获取客户列表
onLoad(() => {
  if (!userStore.token || !['ADMIN', 'CUSTOMER_SERVICE'].includes(userStore.userInfo.role)) {
    uni.navigateTo({ url: '/pages/admin/login' });
    return;
  }
  getCustomerList();
});

onShow(() => {
  filterForm.value.pageNum = 1;
  customerList.value = [];
  getCustomerList();
});

// 获取客户列表
const getCustomerList = async () => {
  if (!hasMore.value || isLoadingMore.value) return;
  isLoadingMore.value = true;

  // 构造请求参数
  const params = {
    pageNum: filterForm.value.pageNum,
    pageSize: filterForm.value.pageSize,
    userType: userTypeList.value[filterForm.value.userTypeIndex].value,
    orderStatus: orderStatusList.value[filterForm.value.orderStatusIndex].value,
    keyword: filterForm.value.keyword.trim()
  };

  try {
    const res = await request({
      url: '/api/admin/customer/list',
      method: 'GET',
      params
    });
    if (res.success) {
      const data = res.data.list || [];
      if (filterForm.value.pageNum === 1) {
        customerList.value = data;
      } else {
        customerList.value = [...customerList.value, ...data];
      }
      hasMore.value = filterForm.value.pageNum * filterForm.value.pageSize < res.data.total;
      filterForm.value.pageNum += 1;
    }
  } catch (error) {
    uni.showToast({ title: '客户列表加载失败', icon: 'none' });
  } finally {
    isLoadingMore.value = false;
  }
};

// 用户类型变化
const handleUserTypeChange = (e) => {
  filterForm.value.userTypeIndex = e.detail.value;
  handleFilterChange();
};

// 下单状态变化
const handleOrderStatusChange = (e) => {
  filterForm.value.orderStatusIndex = e.detail.value;
  handleFilterChange();
};

// 筛选条件变化
const handleFilterChange = () => {
  filterForm.value.pageNum = 1;
  customerList.value = [];
  getCustomerList();
};

// 搜索防抖
const debounceSearch = () => {
  clearTimeout(searchTimer);
  searchTimer = setTimeout(() => {
    filterForm.value.pageNum = 1;
    customerList.value = [];
    getCustomerList();
  }, 500);
};

// 重置筛选
const resetFilter = () => {
  filterForm.value.keyword = '';
  filterForm.value.pageNum = 1;
  customerList.value = [];
  getCustomerList();
};

// 格式化时间
const formatTime = (time) => {
  if (!time) return '';
  const date = new Date(time);
  return `${date.getFullYear()}-${(date.getMonth() + 1).toString().padStart(2, '0')}-${date.getDate().toString().padStart(2, '0')}`;
};

// 跳转客户详情页
const goToCustomerDetail = (customerId) => {
  uni.navigateTo({ url: `/pages/admin/customer/detail?customerId=${customerId}` });
};
</script>

